#include <stdio.h>
int solve(int n, int key, int v[]) {
  int res = -1;
  for (int i = n - 1; i >= 0; i--) {
    if (v[i] == key) {
      res = i;
      break;
    }
  }
  return res;
}

int main() {
  int n = 7;
  int key = 13;
  int v[] = {3, 4, 13, 13, 13, 20, 40};
  printf("%d\n", solve(n, key, v));
  return 0;
}

